settings.custom_css:
/*animasi zoom in awal buka link*/
 
.info_modalx{
  padding: 10px;
  animation: zoom-in 3s ease-out;
}
/*penambahan text di bawah tombol buka undangan. jenis dan ukuran font silakan kreasikan sesuai kebutuhan*/

@import url('https://fonts.googleapis.com/css2?family=Baumans&amp;display=swap');
    
.wdp-button-wrapper::after{
  
    display: block;
    font-family: 'Baumans', cursive;
    font-size: 14px;
     color: #000000;
    margin: 5px 0 0 0;
}


/* wdp dear to */
.wdp-dear{
    margin-top: 50px !important;
    animation: zoom-in 4s ease-out;
}

.wdp-dear:after{
    content: " ";
    display: block;
    animation: zoom-in 4.5s ease-out;
}

.wdp-name{
    animation: zoom-in 7s ease-out;
}

@keyframes zoom-in {
  0% {
    transform: scale(0);
  }
  100% {
    transform: scale(1);
  }
}
/*slide to top */
.removeModals {
    transform: translateY(-200%);
    transition: 2s ease-in-out;
}

/* Ganti Avatar Komen */
.cui-wrapper ul.cui-container-comments li.cui-item-comment .cui-comment-avatar img {
background-image: url("MASUKAN LINK UNTUK FOTO AVATAR");
background-repeat: no-repeat;
margin-right: 10px !important;
padding: 30px; 
background-size: 100%;
}
/* Kotak Konfirmasi Kehadiran */
.cui_comment_count_card {
border-radius: 8px;
text-align: center;
display: flex;
flex-flow: column;
align-items: center;
justify-content: center;
border: 1px solid;
padding: 1px;
color: #fff;
}
.cui_comment_count_card_row {
display: grid;
grid-template-columns: repeat(3,minmax(0,1fr));
gap: -10rem;
}

/* Font Angka Konfirmasi Kehadiran */
.cui_comment_count_card span:first-child {
font-family: alice !important;
font-size: 20px;
font-weight: bolder;
}

/* Font Konfirmasi Kehadiran */
.cui_comment_count_card{
font-family: alice !important;
font-size: 12px;
}

/*Warna Box*/
.cui_comment_count_card.cui_card-hadir {
background-color: #D58E69;
}

.cui_comment_count_card.cui_card-tidak_hadir {
background-color: #91877F;
}

.cui_comment_count_card.cui_card-masih_ragu {
background-color: #B7A999;
}

page_settings.custom_css:
body {
    background-color: #FCDEDC;
}

.goyang-1 img {
	animation-name: goyang1;
    animation-duration: 7s;
    animation-iteration-count: infinite;
    animation-timing-function: linear;
}

.goyang-2 img {
	animation-name: goyang1;
    animation-duration: 5s;
    animation-iteration-count: infinite;
    animation-timing-function: linear;
}

.goyang-3 img {
	animation-name: goyang1;
    animation-duration: 3s;
    animation-iteration-count: infinite;
    animation-timing-function: linear;
}

.goyang-4 img {
	animation-name: goyang4;
    animation-duration: 5s;
    animation-iteration-count: infinite;
    animation-timing-function: linear;
}

.zoom-1 {
	transform: scale(1);
	animation: zoom 3s infinite;
}

.zoom-2 img {
	transform: scale(1);
	animation: zoom 2s infinite;
}

.naik-turun {
	animation-name: naikturun;
    animation-duration: 2s;
    animation-iteration-count: infinite;
    animation-timing-function: linear;
}

@keyframes goyang1{
    0%{ transform: rotate(0deg) scale(1); }
    50%{ transform: rotate(6deg) scale(1.18); }
    100%{ transform: rotate(0deg) scale(1); }
}

@keyframes goyang2{
    0%{ transform: rotate(0deg) scale(1); }
    25%{ transform: rotate(-4deg) scale(1.05); }
    50%{ transform: rotate(-8deg) scale(1.1); }
    75%{ transform: rotate(-4deg) scale(1.05); }
    100%{ transform: rotate(0deg) scale(1); }
}

@keyframes goyang3{
    0%{ transform: rotate(0deg) scale(1); }
    25%{ transform: rotate(-4deg) scale(1.1); }
    50%{ transform: rotate(0deg) scale(1); }
    75%{ transform: rotate(4deg) scale(1.1); }
    100%{ transform: rotate(0deg) scale(1); }
}

@keyframes goyang4{
    0%{ transform: rotate(0deg); }
    25%{ transform: rotate(-4deg); }
    75%{ transform: rotate(4deg); }
    100%{ transform: rotate(0deg); }
}

@keyframes zoom {
	0% { transform: scale(0.95); }
	60% { transform: scale(1); }
	100% { transform: scale(0.95); }
}

@keyframes naikturun {
	0% { transform: translate(0px,0px); }
	50% { transform: translate(0px,-10px); }
	100% { transform: translate(0px,0px); }
}
